use strict;
use warnings;

sub is_prime {
    my ($number) = @_;
    return 0 if $number < 2;

    for my $i (2 .. int(sqrt($number))) {
        return 0 if $number % $i == 0;
    }
    return 1;
}

print "1-50 arasindaki asal sayilar:\n";
my @primes = grep { is_prime($_) } 1 .. 50;
print join(", ", @primes) . "\n";

print "\nToplam asal sayi adedi: " . scalar(@primes) . "\n";

# Tekil kontrol
my $test_number = 97;
print "\n$test_number asal mi: " . (is_prime($test_number) ? "evet" : "hayir") . "\n";

$test_number = 100;
print "$test_number asal mi: " . (is_prime($test_number) ? "evet" : "hayir") . "\n";
